const fs = require('fs').promises;
const path = require('path');

async function replaceInFile(filePath, searchString, replacement) {
  try {
    const fileContent = await fs.readFile(filePath, 'utf8');
    const updatedContent = fileContent.replace(new RegExp(searchString, 'g'), replacement);
    await fs.writeFile(filePath, updatedContent, 'utf8');
  } catch (error) {
    console.error(`err process file ${filePath}: ${error}`);
  }
}

async function processFilesRecursively(rootDirectory, searchString, replacement) {
  try {
    const files = await fs.readdir(rootDirectory);
    for (const file of files) {
      const filePath = path.join(rootDirectory, file);
      const stat = await fs.stat(filePath);

      if (stat.isDirectory()) {
        await processFilesRecursively(filePath, searchString, replacement);
      } else if (file.endsWith('.ts') || file.endsWith('.tsx')) {
        await replaceInFile(filePath, searchString, replacement);
      }
    }
  } catch (error) {
    console.error(`err list directory ${rootDirectory}: ${error}`);
  }
}

const sourceDirectory = `node_modules/@semparar/mf-app-user/src/screens/Login`;
const sourceDirectoryMiddleware = `node_modules/@semparar/mf-app-user/src/redux/sagas/user/login`;
const sourceDirectoryFirstAccess = `node_modules/@semparar/mf-app-user/src/screens/FirstAccess`;

(async () => {
  await processFilesRecursively(sourceDirectory, 'transform="capitalize"', '');
  await processFilesRecursively(
    sourceDirectory,
    '<H1 position="absolute">Faça seu login</H1>',
    '<H1 position="relative">Faça seu login</H1>'
  );
  await processFilesRecursively(sourceDirectoryMiddleware, 'RNBootSplash', 'BootSplash');

  await processFilesRecursively(
    sourceDirectoryFirstAccess,
    '~/redux/ducks/spPay',
    '@semparar/mf-app-accession/src/redux/ducks/spPay'
  );

  await processFilesRecursively(sourceDirectoryFirstAccess, `SPPAYTypes;`, `SPPayTypes;`);

  await processFilesRecursively(sourceDirectoryFirstAccess, 'SPPAYActions,', 'SPPayActions,');

  console.log(
    'success remove component link props transform="capitalize" screen login, change imports and calls rnbootsplash for bootsplash'
  );
})();

